eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   articles: () => (/* binding */ articles),\n/* harmony export */   getAllSlugs: () => (/* binding */ getAllSlugs),\n/* harmony export */   getArticleBySlug: () => (/* binding */ getArticleBySlug),\n/* harmony export */   getLatestArticles: () => (/* binding */ getLatestArticles)\n/* harmony export */ });\nconst articles = [\n    {\n        slug: \"vad-kostar-solceller\",\n        title: \"Vad kostar solceller? Prisguide 2025\",\n        description: \"S\\xe5 mycket kostar solceller f\\xf6r ett villa\\xe4gare 2025 – inklusive installation, batteri och bidrag. J\\xe4mf\\xf6r pris per kWp och f\\xe5 tips f\\xf6r b\\xe4sta deal.\",\n        date: \"2025-03-01\",\n        excerpt: \"En genomg\\xe5ng av solcellspriser 2025: vad du kan f\\xf6rv\\xe4nta dig betala f\\xf6r en komplett anl\\xe4ggning, hur pris per kWp ser ut och vilka bidrag som finns.\",\n        category: \"Pris & ekonomi\",\n        body: [\n            {\n                type: \"p\",\n                content: \"Kostnaden f\\xf6r solceller har sjunkit stadigt under senare \\xe5r, samtidigt som elpriserna \\xf6kat. Det g\\xf6r att \\xe5terbetalningstiden f\\xf6r en solcellsanl\\xe4ggning ofta ligger p\\xe5 8–12 \\xe5r f\\xf6r en villa. H\\xe4r f\\xe5r du en tydlig prisguide s\\xe5 du vet vad du kan f\\xf6rv\\xe4nta dig.\"\n            },\n            {\n                type: \"h2\",\n                content: \"Prisintervall f\\xf6r solceller 2025\"\n            },\n            {\n                type: \"p\",\n                content: \"F\\xf6r en typisk villa med en anl\\xe4ggning p\\xe5 5–10 kWp (kilowattpeak) ligger totalkostnaden oftast mellan 75 000 och 180 000 kr, inklusive installation och material. Priset per installerad kWp brukar ligga runt 15 000–22 000 kr. St\\xf6rre anl\\xe4ggningar ger ofta l\\xe4gre kilowattpris p\\xe5 grund av skalf\\xf6rdelar.\"\n            },\n            {\n                type: \"h3\",\n                content: \"Vad p\\xe5verkar priset?\"\n            },\n            {\n                type: \"ul\",\n                items: [\n                    \"Anl\\xe4ggningens storlek (antal paneler och effekt i kWp)\",\n                    \"Takets l\\xe4ge, lutning och eventuella skuggor\",\n                    \"Val av paneler och v\\xe4xelriktare (m\\xe4rke och effekt)\",\n                    \"Om du l\\xe4gger till solcellsbatteri\",\n                    \"Installat\\xf6rens pris och omfattning av garantier\"\n                ]\n            },\n            {\n                type: \"h2\",\n                content: \"Bidrag och skattereduktion\"\n            },\n            {\n                type: \"p\",\n                content: \"Som hush\\xe5ll kan du f\\xe5 60 \\xf6re per kWh producerad solel (skattereduktion f\\xf6r solel). Det minskar den effektiva kostnaden och f\\xf6rkortar \\xe5terbetalningstiden. Det kan ocks\\xe5 finnas kommunala eller regionala st\\xf6d – kolla vad som g\\xe4ller i din kommun.\"\n            },\n            {\n                type: \"p\",\n                content: \"Genom att j\\xe4mf\\xf6ra offerter fr\\xe5n flera installat\\xf6rer via Nexosol kan du hitta en bra balans mellan pris och kvalitet. Vi kopplar dig till upp till fyra kvalitetss\\xe4krade installat\\xf6rer – kostnadsfritt och bindningsfritt.\"\n            }\n        ]\n    },\n    {\n        slug: \"hur-mycket-solceller-behover-jag\",\n        title: \"Hur mycket solceller beh\\xf6ver jag? Guide till storlek och effekt\",\n        description: \"R\\xe4kna ut hur stor solcellsanl\\xe4ggning du beh\\xf6ver utifr\\xe5n elf\\xf6rbrukning, takyta och geografi. Enkla riktv\\xe4rden och tips f\\xf6r villa\\xe4gare.\",\n        date: \"2025-02-28\",\n        excerpt: \"En guide som hj\\xe4lper dig ta fram r\\xe4tt anl\\xe4ggningsstorlek utifr\\xe5n din f\\xf6rbrukning och tillg\\xe4nglig takyta.\",\n        category: \"Fakta & planering\",\n        body: [\n            {\n                type: \"p\",\n                content: \"F\\xf6r att veta hur stor solcellsanl\\xe4ggning du beh\\xf6ver beh\\xf6ver du titta p\\xe5 din \\xe5rliga elf\\xf6rbrukning (kWh), tillg\\xe4nglig takyta och var i landet du bor. Med n\\xe5gra enkla riktv\\xe4rden kan du f\\xe5 en bra f\\xf6rsta uppskattning.\"\n            },\n            {\n                type: \"h2\",\n                content: \"F\\xf6rbrukning och produktion\"\n            },\n            {\n                type: \"p\",\n                content: \"En tumregel \\xe4r att en solcellsanl\\xe4ggning i s\\xf6dra och mellersta Sverige producerar cirka 900–1 000 kWh per installerad kWp och \\xe5r. En familj som f\\xf6rbrukar 6 000 kWh/\\xe5r kan allts\\xe5 i teorin t\\xe4cka en stor del av f\\xf6rbrukningen med en anl\\xe4ggning p\\xe5 cirka 6 kWp – om taket till\\xe5ter och du har n\\xe5gon form av lagring eller n\\xe4tavtal.\"\n            },\n            {\n                type: \"h3\",\n                content: \"Takyta och effekt\"\n            },\n            {\n                type: \"p\",\n                content: \"Per kWp beh\\xf6vs ungef\\xe4r 5–7 m\\xb2 takyta (beroende p\\xe5 paneleffekt). F\\xf6r 6 kWp r\\xe4knar man ofta med cirka 30–40 m\\xb2. Det \\xe4r viktigt att taket har l\\xe4mplig lutning (g\\xe4rna 25–40\\xb0) och ligger mot s\\xf6der eller i sydv\\xe4st/sydost f\\xf6r b\\xe4st utnyttjande.\"\n            },\n            {\n                type: \"h2\",\n                content: \"N\\xe4sta steg\"\n            },\n            {\n                type: \"p\",\n                content: \"Anv\\xe4nd Nexosols kalkylator f\\xf6r att f\\xe5 en grov uppskattning utifr\\xe5n din f\\xf6rbrukning och takyta. Sedan kan du beg\\xe4ra offerter fr\\xe5n installat\\xf6rer som kan g\\xf6ra en mer exakt bed\\xf6mning utifr\\xe5n din adress och dina \\xf6nskem\\xe5l.\"\n            }\n        ]\n    },\n    {\n        slug: \"ar-solceller-lonsamt\",\n        title: \"\\xc4r solceller l\\xf6nsamt? ROI och \\xe5terbetalning 2025\",\n        description: \"\\xc4r solceller v\\xe4rt det? H\\xe4r f\\xe5r du svar p\\xe5 l\\xf6nsamhet, \\xe5terbetalningstid och vad som p\\xe5verkar ROI f\\xf6r solceller i Sverige.\",\n        date: \"2025-02-25\",\n        excerpt: \"En genomg\\xe5ng av l\\xf6nsamhet och \\xe5terbetalning f\\xf6r solceller – vad som styr ROI och hur du t\\xe4nker som villa\\xe4gare.\",\n        category: \"Pris & ekonomi\",\n        body: [\n            {\n                type: \"p\",\n                content: \"F\\xf6r de flesta villa\\xe4gare med l\\xe4mpligt tak \\xe4r solceller idag en l\\xf6nsam investering. \\xc5terbetalningstiden beror p\\xe5 investeringskostnad, elpris, produktion och eventuell skattereduktion – men 8–12 \\xe5r \\xe4r vanliga intervall.\"\n            },\n            {\n                type: \"h2\",\n                content: \"Vad styr l\\xf6nsamheten?\"\n            },\n            {\n                type: \"ul\",\n                items: [\n                    \"Investeringskostnad (pris per kWp och val av installat\\xf6r)\",\n                    \"Din elf\\xf6rbrukning och n\\xe4r du anv\\xe4nder elen\",\n                    \"Elpriser och n\\xe4tavgifter (nu och f\\xf6rv\\xe4ntat fram\\xe5t)\",\n                    \"Skattereduktion f\\xf6r solel (60 \\xf6re/kWh)\",\n                    \"Om du har batteri och kan lagra \\xf6verskott\"\n                ]\n            },\n            {\n                type: \"h3\",\n                content: \"Livsl\\xe4ngd och underh\\xe5ll\"\n            },\n            {\n                type: \"p\",\n                content: \"Solceller har ofta 25 \\xe5rs garanti med bibeh\\xe5llen h\\xf6g prestanda. Underh\\xe5llskostnaderna \\xe4r normalt l\\xe5ga (reng\\xf6ring, eventuell kontroll). Det inneb\\xe4r att du efter \\xe5terbetalning ofta har m\\xe5nga \\xe5r med netto besparing.\"\n            },\n            {\n                type: \"p\",\n                content: \"Vill du veta hur l\\xf6nsamt det kan bli just f\\xf6r dig? Anv\\xe4nd v\\xe5r kalkylator och beg\\xe4r sedan offerter fr\\xe5n kvalitetss\\xe4krade installat\\xf6rer via Nexosol – helt kostnadsfritt.\"\n            }\n        ]\n    },\n    {\n        slug: \"underhall-av-solceller\",\n        title: \"Underh\\xe5ll av solceller – s\\xe5 h\\xe5ller du anl\\xe4ggningen i trim\",\n        description: \"Beh\\xf6ver solceller underh\\xe5ll? H\\xe4r f\\xe5r du konkreta tips p\\xe5 reng\\xf6ring, kontroller och livsl\\xe4ngd s\\xe5 att din anl\\xe4ggning presterar l\\xe4nge.\",\n        date: \"2025-02-20\",\n        excerpt: \"Praktiska r\\xe5d om underh\\xe5ll av solceller: hur ofta reng\\xf6ra, vad du ska titta efter och n\\xe4r besiktning kan vara v\\xe4rd.\",\n        category: \"Fakta & planering\",\n        body: [\n            {\n                type: \"p\",\n                content: \"Solceller kr\\xe4ver relativt lite underh\\xe5ll, men enkel reng\\xf6ring och n\\xe5gon kontroll g\\xf6r att anl\\xe4ggningen h\\xe5ller sig effektiv under m\\xe5nga \\xe5r. H\\xe4r \\xe4r vad du beh\\xf6ver veta.\"\n            },\n            {\n                type: \"h2\",\n                content: \"Reng\\xf6ring av solpaneler\"\n            },\n            {\n                type: \"p\",\n                content: \"I Sverige bygger det ofta upp damm, pollen och alg p\\xe5 panelerna. En eller tv\\xe5 reng\\xf6ringar per \\xe5r – s\\xe4rskilt p\\xe5 v\\xe5ren – kan ge n\\xe5gra procent h\\xf6gre produktion. Anv\\xe4nd mjuk borste och vatten; undvik skarpa reng\\xf6ringsmedel som kan skada ytan. Vid tak som \\xe4r sv\\xe5ra att n\\xe5 s\\xe4kert \\xe4r det v\\xe4rt att anlita en professionell.\"\n            },\n            {\n                type: \"h3\",\n                content: \"Kontroller och fels\\xf6kning\"\n            },\n            {\n                type: \"p\",\n                content: \"H\\xe5ll koll p\\xe5 att v\\xe4xelriktaren visar normal produktion (via display eller app). Vid pl\\xf6tslig kraftig minskning kan det r\\xf6ra sig om fel p\\xe5 v\\xe4xelriktare, kabel eller panel – d\\xe5 \\xe4r det dags att kontakta installat\\xf6ren eller en besiktningsfirma.\"\n            },\n            {\n                type: \"h2\",\n                content: \"Livsl\\xe4ngd\"\n            },\n            {\n                type: \"p\",\n                content: \"V\\xe4l installerade solceller med bra komponenter h\\xe5ller ofta 25–30 \\xe5r eller l\\xe4ngre. Regelbundet underh\\xe5ll och eventuell besiktning efter 10–15 \\xe5r hj\\xe4lper dig att maximera b\\xe5de livsl\\xe4ngd och produktion.\"\n            }\n        ]\n    },\n    {\n        slug: \"vilka-tak-passar-for-solceller\",\n        title: \"Vilka tak passar f\\xf6r solceller? Lutning, l\\xe4ge och material\",\n        description: \"Alla tak passar inte lika bra f\\xf6r solceller. H\\xe4r f\\xe5r du svar p\\xe5 vilka tak som fungerar b\\xe4st, krav p\\xe5 lutning och v\\xe4derstreck.\",\n        date: \"2025-02-15\",\n        excerpt: \"Guide till taktyper, lutning och l\\xe4ge – s\\xe5 du vet om ditt tak \\xe4r l\\xe4mpligt f\\xf6r solceller.\",\n        category: \"Fakta & planering\",\n        body: [\n            {\n                type: \"p\",\n                content: \"Det som styr om ditt tak \\xe4r l\\xe4mpligt f\\xf6r solceller \\xe4r framf\\xf6r allt lutning, v\\xe4derstreck, skugga och takmaterial. Med r\\xe4tt f\\xf6ruts\\xe4ttningar kan n\\xe4stan alla taktyper anv\\xe4ndas.\"\n            },\n            {\n                type: \"h2\",\n                content: \"Lutning och v\\xe4derstreck\"\n            },\n            {\n                type: \"p\",\n                content: \"B\\xe4st produktion f\\xe5r du med tak som vetter mot s\\xf6der och har en lutning p\\xe5 cirka 25–40\\xb0. Sydv\\xe4st och sydost ger ocks\\xe5 bra resultat – ofta med n\\xe5got l\\xe4gre toppproduktion men mer j\\xe4mn f\\xf6rdelning \\xf6ver dagen. Platta tak kan fungera utm\\xe4rkt med st\\xe4llningar som lutar panelerna optimalt.\"\n            },\n            {\n                type: \"h3\",\n                content: \"Takmaterial\"\n            },\n            {\n                type: \"p\",\n                content: \"Vanliga material som betongpannor, lertegel, pl\\xe5ttak och takpapp g\\xe5r bra. Installationen sker med f\\xe4sten som anpassas till just ditt material. Vid papptak eller speciella konstruktioner beh\\xf6ver installat\\xf6ren bed\\xf6ma f\\xe4stet och eventuell genomf\\xf6ring.\"\n            },\n            {\n                type: \"h2\",\n                content: \"Skugga och bygglov\"\n            },\n            {\n                type: \"p\",\n                content: \"Tr\\xe4d, skorstenar och n\\xe4rliggande byggnader kan ge skugga och minska produktionen. En installat\\xf6r kan med kartor och erfarenhet bed\\xf6ma hur mycket skugga som \\xe4r acceptabelt. Kom \\xe4ven ih\\xe5g att kolla om bygglov beh\\xf6vs – ofta kr\\xe4vs det inte f\\xf6r solceller p\\xe5 befintligt tak, men undantag finns.\"\n            },\n            {\n                type: \"p\",\n                content: \"Vill du veta om ditt tak passar? Fyll i v\\xe5r enk\\xe4t och f\\xe5 offerter fr\\xe5n installat\\xf6rer som bes\\xf6ker din adress och ger en skr\\xe4ddarsydd bed\\xf6mning.\"\n            }\n        ]\n    }\n];\nfunction getArticleBySlug(slug) {\n    return articles.find((a)=>a.slug === slug);\n}\nfunction getAllSlugs() {\n    return articles.map((a)=>a.slug);\n}\nfunction getLatestArticles(count) {\n    return [\n        ...articles\n    ].sort((a, b)=>b.date.localeCompare(a.date)).slice(0, count);\n}\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(rsc)/./src/lib/articles.ts\n");

